const YEARS = Array.from({ length: 13 }, (_, i) => 2013 + i);
const METRICS = [
  { key: "emp", label: "Employment", unit: "employees", money: false },
  { key: "sales", label: "Net sales", unit: "€", money: true },
  { key: "capex", label: "Investment (capex)", unit: "€", money: true, note: "Shown as absolute outflow on fixed and intangible assets." },
  { key: "wages", label: "Wage bill", unit: "€", money: true, note: "Total wages incl. social contributions." },
  { key: "avgwage", label: "Avg. wage / employee", unit: "€ per employee", money: true, note: "Derived: wage bill ÷ employees, where both are reported." },
];

const C = {
  treated: "#9E3039",
  treatedSoft: "rgba(158,48,57,0.16)",
  control: "#3E6580",
  controlSoft: "rgba(62,101,128,0.16)",
  ink: "#1C2126",
  sub: "#5C6670",
  line: "#DDE1E0",
  bg: "#F6F7F5",
  card: "#FFFFFF",
};

// ---------- data prep ----------
function getSeries(firm, metric) {
  if (metric === "avgwage") {
    const w = firm.data.wages || {}, e = firm.data.emp || {};
    const out = {};
    for (const y of Object.keys(w)) {
      const emp = e[y];
      if (emp > 0) out[y] = w[y] / emp;
    }
    return out;
  }
  const s = firm.data[metric] || {};
  if (metric === "capex") {
    const out = {};
    for (const y of Object.keys(s)) out[y] = Math.abs(s[y]);
    return out;
  }
  return s;
}

function fmt(v, money) {
  if (v == null || isNaN(v)) return "–";
  const a = Math.abs(v);
  let s;
  if (a >= 1e6) s = (v / 1e6).toFixed(a >= 1e7 ? 0 : 1) + "M";
  else if (a >= 1e3) s = (v / 1e3).toFixed(a >= 1e4 ? 0 : 1) + "k";
  else s = a >= 100 || Number.isInteger(v) ? Math.round(v).toLocaleString() : v.toFixed(1);
  return money ? "€" + s : s;
}
function median(arr) {
  if (!arr.length) return null;
  const s = [...arr].sort((a, b) => a - b);
  const m = Math.floor(s.length / 2);
  return s.length % 2 ? s[m] : (s[m - 1] + s[m]) / 2;
}

// event-time index: base = T-1 (fallback T-2), index = 100·v/base
function eventIndexed(firm, metric) {
  const t0 = firm.grantYear ?? firm.t0;
  if (!t0) return null;
  const s = getSeries(firm, metric);
  const base = s[t0 - 1] > 0 ? s[t0 - 1] : s[t0 - 2] > 0 ? s[t0 - 2] : null;
  if (!base) return null;
  const out = {};
  for (let t = -2; t <= 3; t++) {
    const v = s[t0 + t];
    if (v != null) out[t] = (100 * v) / base;
  }
  return Object.keys(out).length >= 3 ? out : null;
}



// ---------- shared UI ----------
function Seg({ options, value, onChange, small }) {
  return (
    <div style={{ display: "inline-flex", flexWrap: "wrap", gap: 4, background: "#ECEEEB", padding: 3, borderRadius: 8 }}>
      {options.map((o) => (
        <button key={o.value} onClick={() => onChange(o.value)}
          style={{
            border: "none", cursor: "pointer", borderRadius: 6,
            padding: small ? "4px 9px" : "6px 12px",
            fontSize: small ? 12 : 13, fontWeight: value === o.value ? 600 : 450,
            background: value === o.value ? C.card : "transparent",
            color: value === o.value ? C.ink : C.sub,
            boxShadow: value === o.value ? "0 1px 2px rgba(0,0,0,0.10)" : "none",
          }}>{o.label}</button>
      ))}
    </div>
  );
}

function GroupDot({ color }) {
  return <span style={{ display: "inline-block", width: 9, height: 9, borderRadius: 5, background: color, marginRight: 6 }} />;
}

function FlagRule() {
  return (
    <div style={{ display: "flex", flexDirection: "column", height: 10, borderRadius: 2, overflow: "hidden", margin: "14px 0 0" }}>
      <div style={{ flex: 2, background: C.treated }} />
      <div style={{ flex: 1, background: "#fff" }} />
      <div style={{ flex: 2, background: C.treated }} />
    </div>
  );
}

function ChartTip({ active, payload, label, money, prefix }) {
  if (!active || !payload || !payload.length) return null;
  const rows = payload.filter((p) => p.value != null);
  return (
    <div style={{ background: C.card, border: `1px solid ${C.line}`, borderRadius: 8, padding: "8px 10px", fontSize: 12, boxShadow: "0 2px 8px rgba(0,0,0,0.08)", maxWidth: 260 }}>
      <div style={{ fontWeight: 600, marginBottom: 4 }}>{prefix || ""}{label}</div>
      {rows.slice(0, 10).map((p) => (
        <div key={p.dataKey} style={{ display: "flex", justifyContent: "space-between", gap: 12 }}>
          <span style={{ color: p.color || p.stroke }}>{p.name}</span>
          <span style={{ fontVariantNumeric: "tabular-nums" }}>{fmt(p.value, money)}</span>
        </div>
      ))}
      {rows.length > 10 && <div style={{ color: C.sub }}>+{rows.length - 10} more…</div>}
    </div>
  );
}

// ---------- Tab 1: Overview ----------
function Overview() {
  const data = useMemo(() =>
    RAW.treated.filter((f) => f.aid).map((f) => ({ name: f.name, aid: f.aid, year: f.grantYear }))
      .sort((a, b) => a.year - b.year || b.aid - a.aid), []);
  const cohortColors = { 2016: "#9E3039", 2017: "#B65A50", 2019: "#C98577", 2020: "#5C7A8F", 2021: "#3E6580" };
  const total = data.reduce((s, d) => s + d.aid, 0);
  const cohorts = [...new Set(data.map((d) => d.year))];
  return (
    <div>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 12, marginBottom: 18 }}>
        {[
          ["Aid awarded", "€" + (total / 1e6).toFixed(1) + "M"],
          ["Beneficiaries", RAW.treated.length],
          ["Control firms", RAW.control.length],
          ["Granting cohorts", cohorts.join(" · ")],
        ].map(([k, v]) => (
          <div key={k} style={{ background: C.card, border: `1px solid ${C.line}`, borderRadius: 10, padding: "12px 18px", minWidth: 130 }}>
            <div style={{ fontSize: 11, textTransform: "uppercase", letterSpacing: 0.6, color: C.sub }}>{k}</div>
            <div style={{ fontSize: 22, fontWeight: 650, fontVariantNumeric: "tabular-nums", marginTop: 2 }}>{v}</div>
          </div>
        ))}
      </div>
      <p style={{ fontSize: 13, color: C.sub, margin: "0 0 8px" }}>
        Aid element per beneficiary, coloured by year of granting. Hover for details.
      </p>
      <div style={{ background: C.card, border: `1px solid ${C.line}`, borderRadius: 10, padding: "16px 8px 8px" }}>
        <ResponsiveContainer width="100%" height={Math.max(380, data.length * 21)}>
          <BarChart data={data} layout="vertical" margin={{ left: 8, right: 60, top: 0, bottom: 0 }}>
            <CartesianGrid horizontal={false} stroke={C.line} />
            <XAxis type="number" tickFormatter={(v) => "€" + v / 1e6 + "M"} tick={{ fontSize: 11, fill: C.sub }} />
            <YAxis type="category" dataKey="name" width={185} tick={{ fontSize: 11, fill: C.ink }} interval={0} />
            <Tooltip content={<ChartTip money />} cursor={{ fill: "rgba(0,0,0,0.03)" }} />
            <Bar dataKey="aid" name="Aid element" radius={[0, 3, 3, 0]}>
              {data.map((d, i) => <Cell key={i} fill={cohortColors[d.year] || C.treated} />)}
              <LabelList dataKey="year" position="right" style={{ fontSize: 10, fill: C.sub }} />
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

// ---------- Tab 2: Treated vs Control (event study) ----------
function EventStudy() {
  const [metric, setMetric] = useState("emp");
  const [showFirms, setShowFirms] = useState(true);
  const m = METRICS.find((x) => x.key === metric);

  const { chartData, tFirms, cFirms } = useMemo(() => {
    const tF = RAW.treated.map((f) => ({ f, ix: eventIndexed(f, metric) })).filter((x) => x.ix);
    const cF = RAW.control.map((f) => ({ f, ix: eventIndexed(f, metric) })).filter((x) => x.ix);
    const rows = [];
    for (let t = -2; t <= 3; t++) {
      const row = { t, tLabel: t === 0 ? "T0 (grant)" : t > 0 ? "T+" + t : "T−" + -t };
      const tv = tF.map((x) => x.ix[t]).filter((v) => v != null);
      const cv = cF.map((x) => x.ix[t]).filter((v) => v != null);
      row.treated = median(tv); row.control = median(cv);
      row.nT = tv.length; row.nC = cv.length;
      tF.forEach((x) => { row["T_" + x.f.name] = x.ix[t] ?? null; });
      cF.forEach((x) => { row["C_" + x.f.name] = x.ix[t] ?? null; });
      rows.push(row);
    }
    return { chartData: rows, tFirms: tF, cFirms: cF };
  }, [metric]);

  return (
    <div>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 10, alignItems: "center", marginBottom: 12 }}>
        <Seg options={METRICS.map((x) => ({ value: x.key, label: x.label }))} value={metric} onChange={setMetric} />
        <label style={{ fontSize: 13, color: C.sub, display: "flex", alignItems: "center", gap: 6, cursor: "pointer" }}>
          <input type="checkbox" checked={showFirms} onChange={(e) => setShowFirms(e.target.checked)} />
          individual firms
        </label>
      </div>
      <p style={{ fontSize: 13, color: C.sub, margin: "0 0 10px", maxWidth: 720 }}>
        Each firm is aligned to its grant year (beneficiaries) or its matched grant year (control group) and indexed to
        100 in the year before granting. Lines show the <b>group median</b>; faint traces are individual firms. Firms
        without a positive pre-grant base are excluded.
        {m.note ? " " + m.note : ""}
      </p>
      <div style={{ background: C.card, border: `1px solid ${C.line}`, borderRadius: 10, padding: "16px 8px 4px" }}>
        <ResponsiveContainer width="100%" height={420}>
          <LineChart data={chartData} margin={{ left: 4, right: 20, top: 8 }}>
            <CartesianGrid stroke={C.line} vertical={false} />
            <XAxis dataKey="tLabel" tick={{ fontSize: 12, fill: C.sub }} />
            <YAxis tick={{ fontSize: 11, fill: C.sub }} domain={["auto", "auto"]}
              label={{ value: "index, T−1 = 100", angle: -90, position: "insideLeft", style: { fontSize: 11, fill: C.sub } }} />
            <ReferenceLine x="T0 (grant)" stroke={C.sub} strokeDasharray="4 3" />
            <ReferenceLine y={100} stroke={C.line} />
            <Tooltip content={({ active, payload, label }) => {
              if (!active || !payload?.length) return null;
              const row = payload[0]?.payload;
              const main = payload.filter((p) => p.dataKey === "treated" || p.dataKey === "control");
              return (
                <div style={{ background: C.card, border: `1px solid ${C.line}`, borderRadius: 8, padding: "8px 10px", fontSize: 12, boxShadow: "0 2px 8px rgba(0,0,0,0.08)" }}>
                  <div style={{ fontWeight: 600, marginBottom: 4 }}>{label}</div>
                  {main.map((p) => (
                    <div key={p.dataKey} style={{ color: p.stroke }}>
                      {p.name}: <b>{p.value?.toFixed(1)}</b> (n={p.dataKey === "treated" ? row.nT : row.nC})
                    </div>
                  ))}
                </div>
              );
            }} />
            {showFirms && tFirms.map((x) => (
              <Line key={"T" + x.f.name} dataKey={"T_" + x.f.name} name={x.f.name} stroke={C.treatedSoft}
                strokeWidth={1.2} dot={false} isAnimationActive={false} connectNulls legendType="none" activeDot={false} />
            ))}
            {showFirms && cFirms.map((x) => (
              <Line key={"C" + x.f.name} dataKey={"C_" + x.f.name} name={x.f.name} stroke={C.controlSoft}
                strokeWidth={1.2} dot={false} isAnimationActive={false} connectNulls legendType="none" activeDot={false} />
            ))}
            <Line dataKey="treated" name={`Beneficiaries (median of ${tFirms.length})`} stroke={C.treated}
              strokeWidth={3} dot={{ r: 3.5, fill: C.treated }} connectNulls isAnimationActive={false} />
            <Line dataKey="control" name={`Control group (median of ${cFirms.length})`} stroke={C.control}
              strokeWidth={3} strokeDasharray="7 4" dot={{ r: 3.5, fill: C.control }} connectNulls isAnimationActive={false} />
            <Legend wrapperStyle={{ fontSize: 13 }} />
          </LineChart>
        </ResponsiveContainer>
      </div>
      <p style={{ fontSize: 12, color: C.sub, marginTop: 8 }}>
        Descriptive comparison only — matching is by sector (NACE) and period, not a formal causal estimate.
      </p>
    </div>
  );
}

// ---------- Tab 3: Firm explorer ----------
function Explorer() {
  const [metric, setMetric] = useState("emp");
  const [log, setLog] = useState(false);
  const defaultSel = () => new Set(["T|Tukuma Piens", "C|Latvijas maiznieks"]);
  const [sel, setSel] = useState(defaultSel);
  const m = METRICS.find((x) => x.key === metric);

  const firms = useMemo(() => [
    ...RAW.treated.map((f) => ({ ...f, grp: "T" })),
    ...RAW.control.map((f) => ({ ...f, grp: "C" })),
  ], []);

  const toggle = (id) => setSel((s) => { const n = new Set(s); n.has(id) ? n.delete(id) : n.add(id); return n; });

  const selected = firms.filter((f) => sel.has(f.grp + "|" + f.name));
  const chartData = useMemo(() => YEARS.map((y) => {
    const row = { year: y };
    selected.forEach((f) => { const v = getSeries(f, metric)[y]; row[f.grp + "|" + f.name] = v ?? null; });
    return row;
  }), [sel, metric]);

  const shade = (i, grp) => {
    const base = grp === "T" ? [158, 48, 57] : [62, 101, 128];
    const k = 1 - 0.14 * (i % 4);
    return `rgb(${base.map((c) => Math.round(c * k + (1 - k) * 235)).join(",")})`;
  };

  const list = (grp, title, color) => (
    <div style={{ flex: 1, minWidth: 210 }}>
      <div style={{ fontSize: 12, fontWeight: 650, textTransform: "uppercase", letterSpacing: 0.6, color, marginBottom: 6 }}>
        <GroupDot color={color} />{title}
      </div>
      <div style={{ maxHeight: 300, overflowY: "auto", border: `1px solid ${C.line}`, borderRadius: 8, background: C.card }}>
        {firms.filter((f) => f.grp === grp).map((f) => {
          const has = Object.keys(getSeries(f, metric)).length > 0;
          const id = f.grp + "|" + f.name;
          return (
            <label key={id} style={{ display: "flex", gap: 8, alignItems: "baseline", padding: "5px 10px", fontSize: 12.5, cursor: has ? "pointer" : "default", opacity: has ? 1 : 0.4, borderBottom: `1px solid ${C.line}` }}>
              <input type="checkbox" disabled={!has} checked={sel.has(id)} onChange={() => toggle(id)} />
              <span style={{ flex: 1 }}>{f.name}</span>
              <span style={{ color: C.sub, fontSize: 11, fontVariantNumeric: "tabular-nums" }}>
                {f.grp === "T" ? (f.grantYear || "") : "NACE " + (f.nace || "?")}
              </span>
            </label>
          );
        })}
      </div>
    </div>
  );

  return (
    <div>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 10, alignItems: "center", marginBottom: 12 }}>
        <Seg options={METRICS.map((x) => ({ value: x.key, label: x.label }))} value={metric} onChange={setMetric} />
        <label style={{ fontSize: 13, color: C.sub, display: "flex", alignItems: "center", gap: 6, cursor: "pointer" }}>
          <input type="checkbox" checked={log} onChange={(e) => setLog(e.target.checked)} /> log scale
        </label>
        <button onClick={() => setSel(new Set())} style={{ border: `1px solid ${C.line}`, background: C.card, borderRadius: 6, padding: "4px 10px", fontSize: 12, cursor: "pointer", color: C.sub }}>clear selection</button>
      </div>
      <div style={{ background: C.card, border: `1px solid ${C.line}`, borderRadius: 10, padding: "16px 8px 4px", marginBottom: 14 }}>
        <ResponsiveContainer width="100%" height={380}>
          <LineChart data={chartData} margin={{ left: 8, right: 16, top: 8 }}>
            <CartesianGrid stroke={C.line} vertical={false} />
            <XAxis dataKey="year" tick={{ fontSize: 11, fill: C.sub }} />
            <YAxis tick={{ fontSize: 11, fill: C.sub }} scale={log ? "log" : "auto"} domain={log ? [1, "auto"] : ["auto", "auto"]} allowDataOverflow tickFormatter={(v) => fmt(v, m.money)} width={62} />
            <Tooltip content={<ChartTip money={m.money} />} />
            {selected.map((f, i) => {
              const id = f.grp + "|" + f.name;
              return <Line key={id} dataKey={id} name={f.name + (f.grp === "T" ? " (aid)" : " (control)")}
                stroke={shade(i, f.grp)} strokeWidth={2.4} strokeDasharray={f.grp === "C" ? "6 4" : undefined}
                dot={{ r: 2.5 }} connectNulls isAnimationActive={false} />;
            })}
            {selected.filter((f) => f.grp === "T" && f.grantYear).map((f) => (
              <ReferenceLine key={"g" + f.name} x={f.grantYear} stroke={C.treated} strokeDasharray="3 3" strokeOpacity={0.5} />
            ))}
            <Legend wrapperStyle={{ fontSize: 12 }} />
          </LineChart>
        </ResponsiveContainer>
      </div>
      {selected.length === 0 && <p style={{ fontSize: 13, color: C.sub, marginTop: -6 }}>Select firms below to plot them. Dotted vertical lines mark grant years of selected beneficiaries.</p>}
      <div style={{ display: "flex", flexWrap: "wrap", gap: 14 }}>
        {list("T", "Aid recipients", C.treated)}
        {list("C", "Control (not treated)", C.control)}
      </div>
    </div>
  );
}

// ---------- Tab 4: Matched pairs ----------
function Pairs() {
  const [metric, setMetric] = useState("emp");
  const withMatch = useMemo(() => RAW.treated.filter((t) =>
    RAW.control.some((c) => c.nace && t.nace && t.nace.split(" or ").some((n) => c.nace === n.trim()))
  ), []);
  const [firmName, setFirmName] = useState("Tukuma Piens");
  const m = METRICS.find((x) => x.key === metric);
  const t = RAW.treated.find((f) => f.name === firmName) || withMatch[0];
  const matches = RAW.control.filter((c) => c.nace && t.nace && t.nace.split(" or ").some((n) => c.nace === n.trim()));

  const chartData = useMemo(() => {
    const rows = [];
    for (let et = -2; et <= 3; et++) {
      const row = { t: et, tLabel: et === 0 ? "T0" : et > 0 ? "T+" + et : "T−" + -et };
      const ts = getSeries(t, metric);
      if (t.grantYear) row[t.name] = ts[t.grantYear + et] ?? null;
      matches.forEach((c) => { const cs = getSeries(c, metric); if (c.t0) row[c.name] = cs[c.t0 + et] ?? null; });
      rows.push(row);
    }
    return rows;
  }, [firmName, metric]);

  return (
    <div>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 10, alignItems: "center", marginBottom: 12 }}>
        <select value={t.name} onChange={(e) => setFirmName(e.target.value)}
          style={{ padding: "7px 10px", borderRadius: 8, border: `1px solid ${C.line}`, background: C.card, fontSize: 13, maxWidth: 280 }}>
          {withMatch.map((f) => <option key={f.name} value={f.name}>{f.name} — NACE {f.nace}</option>)}
        </select>
        <Seg small options={METRICS.map((x) => ({ value: x.key, label: x.label }))} value={metric} onChange={setMetric} />
      </div>
      <p style={{ fontSize: 13, color: C.sub, margin: "0 0 10px", maxWidth: 720 }}>
        <b style={{ color: C.treated }}>{t.name}</b> (granted {t.grantYear}, aid {fmt(t.aid, true)},
        sector: {t.sector || "NACE " + t.nace}) against its same-NACE control firm{matches.length > 1 ? "s" : ""}:{" "}
        {matches.map((c) => c.name).join(", ") || "none found"}. Levels, aligned to the grant year.
      </p>
      <div style={{ background: C.card, border: `1px solid ${C.line}`, borderRadius: 10, padding: "16px 8px 4px" }}>
        <ResponsiveContainer width="100%" height={400}>
          <LineChart data={chartData} margin={{ left: 8, right: 16, top: 8 }}>
            <CartesianGrid stroke={C.line} vertical={false} />
            <XAxis dataKey="tLabel" tick={{ fontSize: 12, fill: C.sub }} />
            <YAxis tick={{ fontSize: 11, fill: C.sub }} tickFormatter={(v) => fmt(v, m.money)} width={62} />
            <ReferenceLine x="T0" stroke={C.sub} strokeDasharray="4 3" />
            <Tooltip content={<ChartTip money={m.money} />} />
            <Line dataKey={t.name} name={t.name + " (aid)"} stroke={C.treated} strokeWidth={3} dot={{ r: 3.5 }} connectNulls isAnimationActive={false} />
            {matches.map((c, i) => (
              <Line key={c.name} dataKey={c.name} name={c.name + " (control)"} stroke={i ? "#6E8CA3" : C.control}
                strokeWidth={2.5} strokeDasharray="7 4" dot={{ r: 3 }} connectNulls isAnimationActive={false} />
            ))}
            <Legend wrapperStyle={{ fontSize: 13 }} />
          </LineChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

// ---------- App ----------
const TABS = [
  { id: "overview", label: "Scheme overview", el: <Overview /> },
  { id: "event", label: "Treated vs control", el: <EventStudy /> },
  { id: "pairs", label: "Matched pairs", el: <Pairs /> },
  { id: "explorer", label: "Firm explorer", el: <Explorer /> },
];

export default function App() {
  const [tab, setTab] = useState("event");
  return (
    <div style={{ minHeight: "100vh", background: C.bg, color: C.ink, fontFamily: "'Segoe UI', system-ui, -apple-system, sans-serif", fontVariantNumeric: "tabular-nums" }}>
      <div style={{ maxWidth: 1060, margin: "0 auto", padding: "26px 20px 48px" }}>
        <div style={{ fontSize: 11.5, textTransform: "uppercase", letterSpacing: 1.4, color: C.sub }}>
          State aid SA.45422 · Latvia · Regional investment aid
        </div>
        <h1 style={{ fontFamily: "Georgia, 'Times New Roman', serif", fontSize: 30, fontWeight: 600, margin: "6px 0 2px", letterSpacing: -0.3 }}>
          Aid recipients vs the untreated
        </h1>
        <p style={{ fontSize: 14, color: C.sub, margin: "4px 0 0", maxWidth: 760 }}>
          Employment, sales, investment and wages of <span style={{ color: C.treated, fontWeight: 600 }}>34 beneficiary firms</span> compared
          with a <span style={{ color: C.control, fontWeight: 600 }}>sector-matched control group</span> that received no aid, 2013–2025.
        </p>
        <FlagRule />
        <div style={{ display: "flex", flexWrap: "wrap", gap: 6, margin: "18px 0 20px" }}>
          {TABS.map((t) => (
            <button key={t.id} onClick={() => setTab(t.id)}
              style={{
                border: `1px solid ${tab === t.id ? C.ink : C.line}`, cursor: "pointer", borderRadius: 999,
                padding: "7px 16px", fontSize: 13.5, fontWeight: tab === t.id ? 600 : 450,
                background: tab === t.id ? C.ink : C.card, color: tab === t.id ? "#fff" : C.ink,
              }}>{t.label}</button>
          ))}
        </div>
        {TABS.find((t) => t.id === tab).el}
        <p style={{ fontSize: 11.5, color: C.sub, marginTop: 28, borderTop: `1px solid ${C.line}`, paddingTop: 10 }}>
          Source: uploaded workbook “List_of_recipients_SA.xlsx” (sheets: Aid recipients, Firm list, Non treated, Employees,
          Yearly Sales, Investment (capex), Wages salaries). Missing values (“NA”) are left as gaps. Control firms are observed
          for six years (T−2…T+3) around the grant year of their matched beneficiary. Aid amounts are the aid element in EUR,
          summed where a firm received several grants.
        </p>
      </div>
    </div>
  );
}
